    public function docs()
    {
        return view('xenoraa.docs');
    }

    public function docsSection(string $slug)
    {
        $sections = $this->docsData();
        $found = null;
        $index = -1;
        foreach ($sections as $i => $s) {
            if ($s['slug'] === $slug) {
                $found = $s;
                $index = $i;
                break;
            }
        }
        if (!$found) {
            abort(404);
        }
        // Convert markdown to HTML using Parsedown-style simple conversion
        $html = $this->markdownToHtml($found['content']);
        $found['html'] = $html;
        $prev = $index > 0 ? $sections[$index - 1] : null;
        $next = $index < count($sections) - 1 ? $sections[$index + 1] : null;
        $allSections = array_map(fn($s) => ['slug' => $s['slug'], 'title' => $s['title'], 'icon' => $s['icon']], $sections);
        return view('xenoraa.docs-section', compact('found', 'prev', 'next', 'allSections'))->with('section', $found);
    }

    private function markdownToHtml(string $md): string
    {
        // Headers
        $md = preg_replace('/^#### (.+)$/m', '<h4>$1</h4>', $md);
        $md = preg_replace('/^### (.+)$/m', '<h3>$1</h3>', $md);
        $md = preg_replace('/^## (.+)$/m', '<h2>$1</h2>', $md);
        $md = preg_replace('/^# (.+)$/m', '<h1>$1</h1>', $md);
        // Bold & italic
        $md = preg_replace('/\*\*(.+?)\*\*/', '<strong>$1</strong>', $md);
        $md = preg_replace('/\*(.+?)\*/', '<em>$1</em>', $md);
        // Inline code
        $md = preg_replace('/`(.+?)`/', '<code>$1</code>', $md);
        // Blockquotes
        $md = preg_replace('/^> (.+)$/m', '<blockquote>$1</blockquote>', $md);
        // Unordered lists
        $md = preg_replace_callback('/(?:^[*\-] .+\n?)+/m', function($m) {
            $items = preg_replace('/^[*\-] (.+)$/m', '<li>$1</li>', trim($m[0]));
            return '<ul>' . $items . '</ul>';
        }, $md);
        // Ordered lists
        $md = preg_replace_callback('/(?:^\d+\. .+\n?)+/m', function($m) {
            $items = preg_replace('/^\d+\. (.+)$/m', '<li>$1</li>', trim($m[0]));
            return '<ol>' . $items . '</ol>';
        }, $md);
        // Tables
        $md = preg_replace_callback('/(?:^\|.+\|\n)+/m', function($m) {
            $rows = explode("\n", trim($m[0]));
            $html = '<table>';
            $isHeader = true;
            foreach ($rows as $row) {
                if (preg_match('/^\|[-: |]+\|$/', $row)) { $isHeader = false; continue; }
                $cells = array_slice(explode('|', $row), 1, -1);
                $tag = $isHeader ? 'th' : 'td';
                $html .= '<tr>';
                foreach ($cells as $cell) {
                    $html .= "<$tag>" . trim($cell) . "</$tag>";
                }
                $html .= '</tr>';
                $isHeader = false;
            }
            $html .= '</table>';
            return $html;
        }, $md);
        // Paragraphs — wrap lines not already in HTML tags
        $lines = explode("\n", $md);
        $result = [];
        $inBlock = false;
        foreach ($lines as $line) {
            $trimmed = trim($line);
            if (empty($trimmed)) { $inBlock = false; continue; }
            if (preg_match('/^<(h[1-6]|ul|ol|li|table|tr|th|td|blockquote|pre|code)/', $trimmed)) {
                $result[] = $trimmed;
                $inBlock = false;
            } else {
                $result[] = '<p>' . $trimmed . '</p>';
            }
        }
        return implode("\n", $result);
    }

}